-        if (pseInfo.s1oIdx * pseInfo.s1BaseSize + pseInfo.vecCoreOffset +
-            (pseInfo.loopIdx + 1) * pseInfo.vec1S1BaseSize <=
-            pseInfo.s2StartIdx + pseInfo.s2LoopCount * pseInfo.s2BaseNratioSize) {
